// ?? Config ??????????????????????????????????????????????????????????????????
const GIRLS   = ["Maeve", "Elara", "Amara"];
const MAX_PER = 3;

// Fisher-Yates shuffle (in-place)
function shuffle(arr) {
  for (let i = arr.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1));
    [arr[i], arr[j]] = [arr[j], arr[i]];
  }
  return arr;
}

// ?? 1. Collect all items ?????????????????????????????????????????????????????
const allItems = $input.all();

if (!allItems || allItems.length === 0) {
  return [{ json: { error: "No input items found" } }];
}

// ?? 2. Sort by row_number ascending ?????????????????????????????????????????
const sorted = allItems
  .map(item => item.json)
  .sort((a, b) => (a.row_number ?? 0) - (b.row_number ?? 0));

// ?? 3. Filter out any row where Posted contains "Carousel" ???????????????????
const filtered = sorted.filter(row => {
  const posted = (row.Posted ?? "").toLowerCase();
  return !posted.split(/[\s,]+/).includes("carousel");
});

// ?? 4. Group by Girl ?????????????????????????????????????????????????????????
const grouped = {};
for (const girl of GIRLS) {
  grouped[girl] = filtered.filter(row => row.Girl === girl);
}

// ?? 5. Randomly pick up to MAX_PER Ids per girl ??????????????????????????????
const result = {};
for (const girl of GIRLS) {
  const pool     = grouped[girl];
  const shuffled = shuffle([...pool]);
  const picked   = shuffled.slice(0, MAX_PER);
  result[girl]   = picked.map(row => row.Id);
}

// ?? 6. Return one item per girl ???????????????????????????????????????????????
// ?? 6. Return one item per girl, keyed by name ??????????????????????????????????????
return GIRLS.flatMap(girl =>
  result[girl].map(id => ({
    json: {
      girl: girl.toLowerCase(),
      id
    }
  }))
);

const items = $input.all().map(i => i.json);

const grouped = {};
for (const item of items) {
  if (!item.container_id) continue;
  const girl = item.girl;
  if (!grouped[girl]) {
    grouped[girl] = {
      girl,
      token:      item.token,
      account_id: item.account_id,
      caption:    item.caption,
      children:   [],
      file_names: [],
    };
  }
  grouped[girl].children.push(item.container_id);
  grouped[girl].file_names.push(item.file_name);
}

return Object.values(grouped).map(g => ({
  json: g
}));

return $input.all().map(({ json: item }) => {
  const existing = (item.Posted ?? "").trim();
